// Sorteia um boss e o spawna perto do jogador que digitou !boss.
// Roda só depois do gate de admin no flow.
function run(context) {
  const userid = context.trigger && context.trigger.userid;
  if (!userid) return { skipped: 'no userid' };

  const BOSSES = [
    'deerclops', 'bearger', 'moose', 'dragonfly', 'antlion',
    'minotaur', 'klaus', 'toadstool', 'beequeen', 'crabking',
    'malbatross', 'stalker', 'warg'
  ];
  const pick = BOSSES[Math.floor(Math.random() * BOSSES.length)];

  // Spawna 1 do boss sorteado, com um pequeno offset pra não nascer em cima.
  context.sendCommand('spawn_at_player', {
    userid: userid, prefab: pick, count: 1, offset_x: 4, offset_z: 0
  });

  return { boss: pick };
}
